#!/bin/bash\n\n# database.sh\n# 阿里云一键部署 PostgreSQL + TimescaleDB 脚本\n# 包含基础灾备示例\n\n# --- 配置变量 --- START ---\nDB_USER=\"dyeing_user\"\nDB_PASSWORD=\"YourSuperSecurePassword123!\" # <<<<<<< 请务必修改为强密码 >>>>>>>\nDB_NAME=\"dyeing_process_ai\"\n\nPG_DATA_PATH=\"./pgdata\" # PostgreSQL数据存储路径\nPG_PORT=\"5432\"         # PostgreSQL监听端口\n\nBACKUP_PATH=\"./db_backups\" # 数据库备份存储路径\n\n# --- 配置变量 --- END ---\n\necho \"==================================================\"\necho \"    开始部署染整智能化数据库 (PostgreSQL + TimescaleDB) \"\necho \"==================================================\"\n\n# 1. 检查并安装 Docker 和 Docker Compose\nif ! command -v docker &> /dev/null\nthen\n    echo \"Docker 未安装，正在安装...\"\n    sudo apt-get update\n    sudo apt-get install -y ca-certificates curl gnupg\n    sudo install -m 0755 -d /etc/apt/keyrings\n    curl -fsSL https://download.docker.com/linux/ubuntu/gpg | sudo gpg --dearmor -o /etc/apt/keyrings/docker.gpg\n    sudo chmod a+r /etc/apt/keyrings/docker.gpg\n    echo \\\n      \"deb [arch=\"$(dpkg --print-architecture)\" signed-by=/etc/apt/keyrings/docker.gpg] https://download.docker.com/linux/ubuntu \\\n      \"$(. /etc/os-release && echo \"$VERSION_CODENAME\")\" stable\" | \\\n      sudo tee /etc/apt/sources.list.d/docker.list > /dev/null\n    sudo apt-get update\n    sudo apt-get install -y docker-ce docker-ce-cli containerd.io docker-buildx-plugin docker-compose-plugin\n    sudo usermod -aG docker $USER\n    echo \"Docker 安装完成。请退出并重新登录，或运行 'newgrp docker' 以使 Docker 命令生效。\"\n    echo \"脚本将尝试继续运行，但可能需要重新登录。\"\n    newgrp docker # 尝试立即激活组权限\nelse\n    echo \"Docker 已安装。\"\nfi\n\nif ! command -v docker-compose &> /dev/null\nthen\n    echo \"Docker Compose 未安装，正在安装...\"\n    # Docker Compose V2 是作为 docker-compose plugin 安装的\n    # 检查 docker-compose 命令，如果不存在，则可能是旧版或需要单独安装\n    if ! docker compose version &> /dev/null; then\n        echo \"Docker Compose V2 (docker compose) 未找到，请手动安装或确认Docker Compose插件已安装。\"\n        echo \"你可以尝试：sudo apt-get install docker-compose\" # 对于旧版Docker\n        # 退出，让用户手动处理\n        exit 1\n    fi\n    echo \"Docker Compose 已安装。\"\nelse\n    echo \"Docker Compose 已安装。\"\nfi\n\n# 2. 创建数据和备份目录\nmkdir -p \"$PG_DATA_PATH\"\nmkdir -p \"$BACKUP_PATH\"\n\n# 3. 创建 docker-compose.yml 文件\ncat <<EOF > docker-compose.yml\nversion: '3.8'\n\nservices:\n  db:\n    image: timescale/timescaledb-postgresql:16-latest\n    container_name: dyeing_process_ai_db\n    environment:\n      POSTGRES_DB: \${DB_NAME}\n      POSTGRES_USER: \${DB_USER}\n      POSTGRES_PASSWORD: \${DB_PASSWORD}\n      # 允许从任何IP连接 (开发/测试用，生产环境请限制IP)\n      PGHOST: 0.0.0.0\n    volumes:\n      - \${PG_DATA_PATH}:/var/lib/postgresql/data\n      # 挂载SQL文件用于初始化\n      - ./database.sql:/docker-entrypoint-initdb.d/init.sql\n    ports:\n      - \"\${PG_PORT}:\${PG_PORT}\"\n    restart: unless-stopped\n    healthcheck:\n      test: [\"CMD-SHELL\", \"pg_isready -U \${DB_USER} -d \${DB_NAME}\"]\n      interval: 10s\n      timeout: 5s\n      retries: 5\n\nnetworks:\n  default:\n    driver: bridge\nEOF\n\n# 4. 启动数据库服务\necho \"正在启动数据库服务...\"\n# 使用 env_file 来传递环境变量，更安全和灵活\ncat <<EOF > .env\nDB_NAME=${DB_NAME}\nDB_USER=${DB_USER}\nDB_PASSWORD=${DB_PASSWORD}\nPG_DATA_PATH=${PG_DATA_PATH}\nPG_PORT=${PG_PORT}\nEOF\ndocker compose up -d\n\necho \"等待数据库启动并初始化...\"\n# 等待数据库健康检查通过\ndocker compose exec db pg_isready -U \"$DB_USER\" -d \"$DB_NAME\" -t 0 > /dev/null 2>&1\nwhile [ $? -ne 0 ]\ndo\n    echo \"数据库仍在启动...\"\n    sleep 5\n    docker compose exec db pg_isready -U \"$DB_USER\" -d \"$DB_NAME\" -t 0 > /dev/null 2>&1\ndone\n\necho \"数据库已成功启动并初始化！\"\necho \"您可以通过以下命令连接到数据库：\"\necho \"psql -h localhost -p ${PG_PORT} -U ${DB_USER} -d ${DB_NAME}\"\n\n# 5. 灾备示例\necho \"\\n==================================================\"\necho \"    灾备操作示例 (请在生产环境中使用更专业的方案) \"\necho \"==================================================\"\n\n# 物理备份示例 (pg_basebackup)\n# 停止数据库进行一致性物理备份 (不推荐在生产环境直接停止)\n# docker compose stop db\n# echo \"正在执行物理备份 (需要数据库停止或配置WAL归档)...\"\n# docker run --rm -v \$(pwd)/${BACKUP_PATH}:/backup -v \$(pwd)/${PG_DATA_PATH}:/var/lib/postgresql/data timescale/timescaledb-postgresql:16-latest pg_basebackup -h db -U ${DB_USER} -D /backup/physical_backup_$(date +%Y%m%d_%H%M%S) -F t -P -v\n# docker compose start db\n# echo \"物理备份完成。\"\n\n# 逻辑备份示例 (pg_dump)\necho \"正在执行逻辑备份...\"\ndocker compose exec db pg_dump -U \"$DB_USER\" -d \"$DB_NAME\" -Fc > \"$BACKUP_PATH/logical_backup_$(date +%Y%m%d_%H%M%S).dump\"\nif [ $? -eq 0 ]; then\n    echo \"逻辑备份完成：$BACKUP_PATH/logical_backup_$(date +%Y%m%d_%H%M%S).dump\"\nelse\n    echo \"逻辑备份失败！\"\nfi\n\n# 恢复示例 (假设数据库已停止并清空数据目录)\n# echo \"\\n恢复逻辑备份示例：\"\n# echo \"  1. 停止数据库: docker compose stop db\"\n# echo \"  2. 清空数据目录: sudo rm -rf ${PG_DATA_PATH}/*\"\n# echo \"  3. 启动数据库: docker compose up -d\"\n# echo \"  4. 执行恢复: docker compose exec db pg_restore -U ${DB_USER} -d ${DB_NAME} < your_backup_file.dump\"\n\necho \"\\n==================================================\"\necho \"    部署完成！ \"\necho \"==================================================\"\n